#include <stdio.h>
#include <stdlib.h>

// Define the structure for a linked list node
typedef struct Node {
    int val;
    struct Node* next;
    struct Node* child;
} Node;

// Function to create a new node
Node* createNode(int val) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    newNode->val = val;
    newNode->next = NULL;
    newNode->child = NULL;
    return newNode;
}

// Function to flatten the linked list
Node* flattenLinkedList(Node* head) {
    // Base case: if the list is empty, return NULL
    if (head == NULL) return NULL;

    // Initialize a list to store the node values
    int* values = (int*) malloc(sizeof(int));
    int size = 0;

    // Function to traverse the linked list and store node values
    void traverse(Node* node) {
        if (node == NULL) return;
        values = (int*) realloc(values, (size + 1) * sizeof(int));
        values[size++] = node->val;
        traverse(node->next);
        traverse(node->child);
    }

    // Traverse the linked list and store node values
    traverse(head);

    // Sort the node values
    for (int i = 0; i < size - 1; i++) {
        for (int j = i + 1; j < size; j++) {
            if (values[i] > values[j]) {
                int temp = values[i];
                values[i] = values[j];
                values[j] = temp;
            }
        }
    }

    // Create a new linked list from the sorted node values
    Node* newHead = createNode(values[0]);
    Node* current = newHead;
    for (int i = 1; i < size; i++) {
        current->next = createNode(values[i]);
        current = current->next;
    }

    // Free the memory allocated for the node values
    free(values);

    return newHead;
}

// Function to print the linked list
void printLinkedList(Node* head) {
    while (head != NULL) {
        printf("%d ", head->val);
        head = head->next;
    }
    printf("\n");
}

int main() {
    // Create a sample linked list
    Node* head = createNode(5);
    head->next = createNode(10);
    head->next->next = createNode(12);
    head->next->next->child = createNode(20);
    head->next->next->child->child = createNode(13);
    head->child = createNode(14);

    // Print the original linked list
    printf("Original linked list: ");
    printLinkedList(head);

    // Flatten the linked list
    Node* flattened = flattenLinkedList(head);

    // Print the flattened linked list
    printf("Flattened linked list: ");
    printLinkedList(flattened);

    return 0;
}

